<script>
function fmtMoneda(v){if(v==null||isNaN(v))return"-";return"$ "+Number(v).toLocaleString("es-AR",{minimumFractionDigits:2,maximumFractionDigits:2})}
function fmtCant(v){if(v==null||isNaN(v))return"-";return Number(v).toLocaleString("es-AR")}
function fmtFecha(iso){if(!iso)return"-";var d=new Date(iso);if(isNaN(d.getTime()))return iso;return d.toLocaleDateString("es-AR",{day:"2-digit",month:"2-digit",year:"numeric"})}
function badge(clasif){var m={"APTO_PARA_PROGRAMAR":{l:"Apto",c:"badge-apto"},"BLOQUEADO":{l:"Bloqueado",c:"badge-bloq"},"PENDIENTE_VALIDACION":{l:"Pendiente",c:"badge-pend"},"REQUIERE_APROBACION_HUMANA":{l:"Requiere Aprobación",c:"badge-aprob"}};var x=m[clasif]||m[clasif];return x?"<span class="badge "+x.c+"">"+x.l+"</span>":""}
async function cargarDatos(){var days=document.getElementById("days").value||30;var t=document.getElementById("tabla");t.innerHTML="<div class="loading-state"><div class="spinner"></div><p>Cargando...</p></div>";try{var r=await fetch("/api/despachos/pendientes?days="+days);if(!r.ok)throw new Error("HTTP "+r.status);var d=await r.json();var k=d.resumen||{};document.getElementById("k1").innerHTML="<span class="kpi-value">"+(k.totalRemitos||0)+"</span><span class="kpi-label">Remitos</span>";document.getElementById("k2").innerHTML="<span class="kpi-value">"+(k.totalClientes||0)+"</span><span class="kpi-label">Clientes</span>";document.getElementById("k3").innerHTML="<span class="kpi-value">"+fmtCant(k.totalBolsas||0)+"</span><span class="kpi-label">Bolsas</span>";document.getElementById("k4").innerHTML="<span class="kpi-value">"+fmtCant(k.totalToneladas||0)+"</span><span class="kpi-label">Toneladas</span>";document.getElementById("k5").innerHTML="<span class="kpi-value">"+fmtMoneda(k.totalImporte||0)+"</span><span class="kpi-label">Importe Total</span>";var data=d.data||[];if(!data.length){t.innerHTML="<div class="empty-state"><p>No se encontraron remitos pendientes</p></div>";return}var html="<div class="table-wrapper"><table><thead><tr><th>Remito</th><th>Fecha</th><th>Cliente</th><th>Producto</th><th class="text-end">Cantidad</th><th>Unidad</th><th class="text-end">Precio</th><th class="text-end">Total</th><th>Transporte</th></tr></thead><tbody>";data.forEach(function(i){html+="<tr><td><button class="btn-link" onclick="verDetalle('"+i.remito+"')">"+i.remito+"</button></td><td>"+fmtFecha(i.fecha)+"</td><td>"+(i.cliente||"-")+"</td><td>"+(i.producto||"-")+"</td><td class="text-end">"+fmtCant(i.cantidad)+"</td><td>"+(i.unidad||"-")+"</td><td class="text-end">"+fmtMoneda(i.precio)+"</td><td class="text-end">"+fmtMoneda(i.totalItem)+"</td><td>"+(i.transportista||"-").substring(0,20)+"</td></tr>"});html+="</tbody></table></div><div style="padding:12px 16px;border-top:1px solid #e2e8f0;font-size:12px;color:#64748b">"+data.length+" remitos</div>";t.innerHTML=html}catch(e){t.innerHTML="<div class="error-state"><p>Error: "+e.message+"</p><p style="font-size:12px;color:#94a3b8">Verificar que Node-RED esté corriendo y las credenciales SQL configuradas</p></div>"}}
function verDetalle(remito){alert("Detalle del remito "+remito+"
(modal completo disponible con httpStatic configurado)")}
document.getElementById("fechaAct").textContent="Actualizado: "+new Date().toLocaleString("es-AR",{day:"2-digit",month:"long",year:"numeric",hour:"2-digit",minute:"2-digit"});
cargarDatos();
</script>
